// AntiPotion — cancel negative effects on player
if (event.getPacket() instanceof S1DPacketEntityEffect) {
  S1DPacketEntityEffect s1d =
    (S1DPacketEntityEffect) event.getPacket();
  if (s1d.getEntityId() == mc.thePlayer.getEntityId()
    && isNegativeEffect(s1d.getEffectId())) {
    event.setCancelled(true);
  }
}
// Effect IDs: 2=slowness, 9=nausea, 15=blindness,
//   18=weakness, 19=poison, 20=wither
